const b = $input.first().json.body || $input.first().json || {};
return [{
  json: {
    respostas_usuario: b.content || b.respostas_usuario || '',
    etp: b.etp_content || b.etp || '',
    pesquisa_precos: b.pesquisa_precos_texto || b.pesquisa_precos || 'Nenhuma pesquisa de preços fornecida.',
    matriz_risco: b.matriz_riscos || b.matriz_risco || '',
    process_id: b.process_id || 'N/A'
  }
}];

// Consolida as 3 seções geradas pelos agentes
const items = $input.all();
const secao1 = items[0]?.json?.output || '';
const secao2 = items[1]?.json?.output || '';
const secao3 = items[2]?.json?.output || '';

// Extrai campos estruturados da Seção 1 para o docxtemplater
// A IA deve ter preenchido os dados reais no texto
const processId = $('Normalizar_Dados').first().json.process_id || 'N/A';

// Monta o texto completo de preview para exibir no frontend
const textoCompleto = [
  secao1,
  '',
  '---',
  '',
  secao2,
  '',
  '---',
  '',
  secao3
].join('\n');

return [{
  json: {
    sucesso: true,
    secoes: {
      secao1,
      secao2,
      secao3
    },
    frontend_preview: {
      secao_requisitos: secao1,
      secao_gestao: secao2,
      secao_infracoes: secao3,
      secao_entregas: ''
    },
    texto_completo: textoCompleto,
    process_id: processId
  }
}];
